#!/usr/bin/env python3
# chat — Layer 1 working memory. Builds turn-based history from the log
# (identity as a system turn + latest compaction summary + the live tail since
# that compaction + the new user message), hands it to `self think`, and emits
# the user and assistant turns. Older turns live in the log; only the tail is replayed.
import sys, json, subprocess, os

user_msg = " ".join(sys.argv[1:]).strip()
events = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        events.append(json.loads(line))
    except Exception:
        pass

identity = ""
summary = ""
through = 0
for e in events:
    n = e.get("name"); p = e.get("payload", {}) or {}
    if n == "self.identity":
        identity = p.get("text", "") or identity
    elif n == "chat.compaction":
        summary = p.get("summary", "") or summary
        through = p.get("through_seq", through) or through

turns = []
if identity:
    turns.append({"role": "system", "content": identity})
if summary:
    turns.append({"role": "system", "content": "Summary of the conversation so far:\n" + summary})
for e in events:
    if e.get("name") == "chat.message" and e.get("seq", 0) > through:
        p = e.get("payload", {}) or {}
        if p.get("role") in ("user", "assistant"):
            turns.append({"role": p["role"], "content": p.get("content", "")})
if user_msg:
    turns.append({"role": "user", "content": user_msg})

response, declarations = "", []
try:
    proc = subprocess.run(["self", "think"], input=json.dumps(turns),
                          capture_output=True, text=True, env=os.environ)
    out = json.loads(proc.stdout)
    response = out.get("response", "")
    declarations = out.get("declarations") or []
except Exception as ex:
    response = "brain unreachable: %s" % ex

if user_msg:
    print(json.dumps({"name": "chat.message", "payload": {"role": "user", "content": user_msg}}))
print(json.dumps({"name": "chat.message", "payload": {"role": "assistant", "content": response}}))
for d in declarations:
    if isinstance(d, dict) and d.get("name"):
        print(json.dumps({"name": d["name"], "payload": d.get("payload", {})}))

#!/usr/bin/env python3
# chat — renders the conversation: the latest compaction summary (collapsed
# history) + the live tail of turns + an input box. Older turns are folded away
# here but never lost in the log.
import sys, json
from html import escape
events = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        events.append(json.loads(line))
    except Exception:
        pass
summary = ""
through = 0
for e in events:
    if e.get("name") == "chat.compaction":
        p = e.get("payload", {}) or {}
        summary = p.get("summary", "") or summary
        through = p.get("through_seq", through) or through
msgs = [e for e in events if e.get("name") == "chat.message" and e.get("seq", 0) > through]
print("<!DOCTYPE html><html><head><meta charset='utf-8'><title>chat</title></head><body>")
print("<h1>chat</h1>")
print("<p class='muted'><a href='/identity'>identity</a> &middot; this conversation is self's working memory; older turns fold into a summary.</p>")
if summary:
    print("<div class='card'><div class='who'>summary so far</div><div>%s</div></div>" % escape(summary))
for e in msgs:
    p = e.get("payload", {}) or {}
    role = p.get("role", "user")
    who = "you" if role == "user" else ("self" if role == "assistant" else role)
    print("<div class='msg'><div class='who'>%s</div><div>%s</div></div>" % (escape(who), escape(p.get("content", ""))))
print("<hr><form method='post' action='/run/chat'><input name='message' placeholder='say something to self...'><button>send</button></form>")
print("</body></html>")
